// ============================================
// GET PERIOD FROM SYSTEM STATE
// ============================================

// Get period from system_state (read by earlier node)
const periodData = $('Read System State').first().json;
const periodStart = periodData.period_start; // e.g., "2026-02-26"
const periodEnd = periodData.period_end;     // e.g., "2026-02-28"

// Convert to timestamps for filtering
const startOfWindowMs = new Date(periodStart + 'T00:00:00').getTime();
const endOfWindowMs = new Date(periodEnd + 'T23:59:59').getTime();

// ============================================
// GET SOURCE ID FROM PREVIOUS NODE
// ============================================

// Get the current row from the "Select Active Sources" node
const sourceRow = $('Select Active Sources').all()[$runIndex];

// Extract the source ID from that row (or use 0 if not found)
const sourceId = sourceRow ? sourceRow.json.id : 0;

// ============================================
// PROCESS RSS ITEMS
// ============================================

const items = $input.all()  // Get all input items from the RSS node

  // Step 1: Extract just the JSON data from each item
  .map(item => item.json)

  // Step 2: Filter - keep only items from the period (excluding today)
  .filter(item => {
    const iso = item.isoDate;  // Get the publish date
    if (!iso) return false;     // Skip if no date found

    const itemTime = new Date(iso).getTime();  // Convert to timestamp

    // Keep item if it's within the period window
    return itemTime >= startOfWindowMs && itemTime <= endOfWindowMs;
  })

  // Step 3: Limit to the 20 most recent items
  .slice(0, 20)

  // Step 4: Transform into the format needed for database insert
  .map(item => ({
    json: {
      sourceid: sourceId,           // Add the source ID from Postgres
      title: item.title,             // RSS article title
      url: item.link,                // RSS article URL
      raw_content: item.content || item.contentSnippet || '',  // Full content (with HTML if available)
      publishedat: item.isoDate      // Publication date in ISO format
        ? new Date(item.isoDate).toISOString() 
        : new Date().toISOString()   // Fallback to current time if date missing
    }
  }));

// ============================================
// RETURN THE PROCESSED ITEMS
// ============================================

return items;  // Send to the next node in the workflow

// Get period from system_state
const periodData = $('Read System State').first().json;

// Get count from SQL node
const itemsInserted = $('Count Inserted Items').first().json.count;

return [{
  json: {
    topic: periodData.topic,
    workflow_id: 1,
    event: 'ingest_complete',
    status: 'success',
    details: {
      period_start: periodData.period_start,
      period_end: periodData.period_end,
      items_inserted: itemsInserted
    }
  }
}];

